using Microsoft.IdentityModel.Tokens;

namespace Axions.Core.Features.Integrations.Queries.GetIntegrations;

/// <summary>
/// GetsIntegrationsQuery
/// </summary>
public class GetIntegrationsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<IntegrationDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Integration, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Integration>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Integration>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Type) && x.Type!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetIntegrationsQuery.
/// </summary>
public class GetIntegrationQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetIntegrationsQuery, BaseResultDto<PaginatedResult<IntegrationDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<IntegrationDto>>> Handle(GetIntegrationsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Integrations
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Integration, IntegrationDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<IntegrationDto>>();
    }
}

